import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg.get('resolvedVersion', pkg.get('requestedVersion',''))
        result[name] = pkgs
    return result

before = extract(b)
after = extract(a)
print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(before.keys()) + list(after.keys()))):
    bp = before.get(proj, {})
    ap = after.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'N/A')
        av = ap.get(pkg, 'N/A')
        if bv != av:
            print(f'{proj}: {pkg} {bv} -> {av}')
            changes = True
if not changes:
    print('No changes')
print()
print('=== ALL RESOLVED ===')
for proj in sorted(after.keys()):
    for pkg, ver in sorted(after[proj].items()):
        print(f'{proj}: {pkg} = {ver}')
"

